    createGrid(width, height) {
        let grid = Array.from({ length: height }, () => Array.from({ length: width }, () => '.'));
        grid = this.placeObstacles(grid, 'T', Math.floor(width * height * 0.1)); // 10% trees
        grid = this.placeObstacles(grid, 'S', Math.floor(width * height * 0.05)); // 5% stones
        return grid;
    }

